"use client";
import { useEffect, useState, Suspense } from "react";
import { useSession } from "next-auth/react";
import { useSearchParams, useRouter } from "next/navigation";
import { Heart, MapPin, Eye, ArrowUpRight, Home, TrendingUp } from "lucide-react";

function PropertiesContent() {
  const { data: session } = useSession();
  const router = useRouter();
  const searchParams = useSearchParams();
  
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cityWiseData, setCityWiseData] = useState({ bilaspur: [], raipur: [], others: [] });

  const search = searchParams.get("search") || "";
  const district = searchParams.get("district") || "";
  const category = searchParams.get("category") || "All";

  // Helper to organize
  const organizeByCity = (props) => {
    const bilaspur = [];
    const raipur = [];
    const others = [];
    
    props.forEach(prop => {
      const city = prop.district?.toLowerCase() || "";
      if (city.includes("bilaspur")) bilaspur.push(prop);
      else if (city.includes("raipur")) raipur.push(prop);
      else others.push(prop);
    });
    
    return {
      bilaspur: bilaspur.slice(0, 10),
      raipur: raipur.slice(0, 10),
      others: others
    };
  };

  useEffect(() => {
    const fetchProperties = async () => {
      setLoading(true);
      try {
        const params = new URLSearchParams();
        if (search) params.set("search", search);
        if (district) params.set("district", district);
        const minPrice = searchParams.get("minPrice");
        const maxPrice = searchParams.get("maxPrice");
        const kitchen = searchParams.get("kitchen");
        const plotType = searchParams.get("plotType");
        if (category && category !== "All") params.set("category", category);
        if (minPrice) params.set("minPrice", minPrice);
        if (maxPrice) params.set("maxPrice", maxPrice);
        if (kitchen) params.set("kitchen", kitchen);
        if (plotType) params.set("plotType", plotType);
        
        const res = await fetch(`/api/properties?${params.toString()}`);
        if (!res.ok) throw new Error("API Response failed");
        const data = await res.json();
        const allProps = data.properties || data;
        setProperties(allProps);
        
        if (category && category !== "All") {
          setCityWiseData(organizeByCity(allProps));
        } else {
          setCityWiseData({ bilaspur: [], raipur: [], others: allProps });
        }
      } catch (err) {
        console.error("Error fetching data:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchProperties();
  }, [search, district, category, searchParams]);

  const handleLike = async (e, propertyId) => {
    e.stopPropagation();
    if (!session) return alert("Pehle Login karo bhai!");
    try {
      const res = await fetch(`/api/properties/${propertyId}/like`, { method: "POST" });
      const data = await res.json();
      if (res.ok) {
        setProperties(properties.map(p => 
          p._id === propertyId ? { ...p, likes: data.likes } : p
        ));
      }
    } catch (err) { console.log(err); }
  };

  // --- LOADING STATE (Sleek) ---
  if (loading) return (
    <div className="h-screen flex items-center justify-center bg-gray-50">
      <div className="flex flex-col items-center gap-4">
        <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        <p className="text-xs font-bold tracking-widest text-gray-400 uppercase">Finding best homes...</p>
      </div>
    </div>
  );

  // --- MODERN CARD COMPONENT ---
  const PropertyCard = ({ item }) => {
    const isLiked = item.likes?.includes(session?.user?.email);
    
    return (
      <div 
        onClick={() => router.push(`/properties/${item._id}`)} 
        className="group bg-white rounded-[2rem] hover:-translate-y-2 transition-all duration-300 shadow-sm hover:shadow-2xl hover:shadow-blue-900/5 cursor-pointer border border-gray-100/50"
      >
        {/* Image Container */}
        <div className="relative h-64 overflow-hidden rounded-t-[2rem]">
          <img 
            src={item.images[0] || "/no-image.png"} 
            alt={item.title} 
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" 
          />
          
          {/* Floating Badges */}
          <div className="absolute top-4 left-4 flex gap-2">
            <span className="bg-white/90 backdrop-blur-md px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider text-gray-800 shadow-sm">
              {item.cat || 'Property'}
            </span>
          </div>

          {/* Like Button */}
          <button 
            onClick={(e) => handleLike(e, item._id)}
            className="absolute top-4 right-4 p-2.5 bg-white/80 backdrop-blur-sm rounded-full shadow-sm hover:bg-white transition-all active:scale-90"
          >
            <Heart size={18} className={isLiked ? "fill-red-500 text-red-500" : "text-gray-400"} />
          </button>
        </div>

        {/* Info Content */}
        <div className="p-6">
          <div className="flex justify-between items-start mb-2">
             <h2 className="text-lg font-black text-gray-900 truncate pr-2 group-hover:text-blue-600 transition-colors">
               {item.title}
             </h2>
             <div className="text-gray-300 group-hover:text-blue-600 transition-colors">
                <ArrowUpRight size={20} />
             </div>
          </div>
          
          <p className="text-gray-400 font-bold text-xs flex items-center gap-1.5 mb-6">
            <MapPin size={14} className="text-gray-400 group-hover:text-red-500 transition-colors" /> 
            {item.district}
          </p>

          {/* Divider */}
          <div className="h-px bg-gray-50 w-full mb-4"></div>

          {/* Bottom Row */}
          <div className="flex justify-between items-center">
            <div>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Price</p>
              <p className="text-xl font-[1000] text-gray-900">
                ₹{item.price.toLocaleString('en-IN')}
              </p>
            </div>
            
            <div className="flex items-center gap-3 bg-gray-50 px-3 py-2 rounded-xl">
               <span className="flex items-center gap-1 text-xs font-bold text-gray-500">
                 <Eye size={14} className="text-gray-400"/> {item.views || 0}
               </span>
               <div className="w-px h-3 bg-gray-300"></div>
               <span className="flex items-center gap-1 text-xs font-bold text-gray-500">
                 <Heart size={14} className="text-gray-400"/> {item.likes?.length || 0}
               </span>
            </div>
          </div>
        </div>
      </div>
    );
  };

  // --- SECTIONS RENDER ---
  const renderCityWiseBlocks = () => {
    // Agar "All" category hai toh plain grid
    if (!category || category === "All") {
      return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {properties.map((item) => <PropertyCard key={item._id} item={item} />)}
        </div>
      );
    }

    const categoryName = category === "Room" ? "Rooms" : category === "PG" ? "PG" : category === "House" ? "Houses" : "Plots";

    // Section Component
    const CitySection = ({ title, data }) => (
      <div className="py-8">
        <div className="flex items-center gap-4 mb-8">
           <h2 className="text-2xl md:text-3xl font-black text-gray-900 tracking-tight">{title}</h2>
           <div className="h-1 flex-1 bg-gray-100 rounded-full mt-1"></div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {data.map((item) => <PropertyCard key={item._id} item={item} />)}
        </div>
      </div>
    );

    return (
      <div className="space-y-4">
        {cityWiseData.bilaspur.length > 0 && <CitySection title={`${categoryName} in Bilaspur`} data={cityWiseData.bilaspur} />}
        {cityWiseData.raipur.length > 0 && <CitySection title={`${categoryName} in Raipur`} data={cityWiseData.raipur} />}
        {cityWiseData.others.length > 0 && <CitySection title="Other Cities" data={cityWiseData.others} />}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-[#FDFDFD]">
      {/* HEADER SECTION */}
      <div className="bg-white border-b border-gray-100 pb-10 pt-16 px-4">
        <div className="max-w-7xl mx-auto">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
            <div>
               <div className="flex items-center gap-2 mb-3">
                 <span className="bg-blue-50 text-blue-600 p-1.5 rounded-lg"><Home size={16} /></span>
                 <p className="text-blue-600 font-bold text-[11px] uppercase tracking-[0.2em]">Real Estate Hub</p>
               </div>
               <h1 className="text-4xl md:text-6xl font-[1000] text-gray-900 tracking-tighter uppercase leading-none">
                 {search || district ? `${district || search}` : category !== "All" ? `${category}s` : "Discover Living"}
               </h1>
            </div>
            
            <div className="flex items-center gap-2 text-gray-500 font-bold text-xs uppercase tracking-widest bg-gray-50 px-5 py-3 rounded-2xl border border-gray-100">
              <TrendingUp size={16} className="text-gray-900" />
              {properties.length} Active Listings
            </div>
          </div>
        </div>
      </div>
      
      {/* CONTENT AREA */}
      <div className="max-w-7xl mx-auto p-4 md:p-10">
        {renderCityWiseBlocks()}
        
        {/* EMPTY STATE */}
        {properties.length === 0 && (
          <div className="flex flex-col items-center justify-center py-40 text-center">
            <div className="bg-gray-50 p-6 rounded-full mb-4">
               <Home size={40} className="text-gray-300" />
            </div>
            <p className="text-gray-900 font-black text-2xl tracking-tight mb-2">No Properties Found</p>
            <p className="text-gray-400 font-medium mb-6">We couldn't find what you're looking for.</p>
            <button 
              onClick={() => router.push('/properties')} 
              className="px-8 py-3 bg-black text-white rounded-full font-bold hover:bg-gray-800 transition-colors"
            >
              Clear Filters
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default function PropertiesPage() {
  return (
    <Suspense fallback={<div className="h-screen flex items-center justify-center font-black text-gray-200">LOADING...</div>}>
      <PropertiesContent />
    </Suspense>
  );
}